import sys
import math

def min_maps_to_study(N, P):
    if P == 0:
        return 0
    if P == 1:
        return N - 1
    left = 0
    right = N
    while left < right:
        mid = (left + right) // 2
        prob = 1 - (math.comb(N - mid, 3) / math.comb(N, 3))
        if prob >= P:
            right = mid
        else:
            left = mid + 1
    return left

def main():
    input_line = sys.stdin.readline().strip()
    N, P = input_line.split()
    N = int(N)
    P = float(P)
    print(min_maps_to_study(N, P))

if __name__ == "__main__":
    main()

